) =>
    // Ported from shaders/escape_time_family/families/burning_ship/parameter_plane/burning_ship_gpu.frag — shader flips Y.
    _escapeTime(x, -y, iterations, bailout, (zx, zy, cx, cy) {
      final ax = zx.abs();
      final ay = zy.abs();
      return (ax * ax - ay * ay + cx, 2.0 * ax * ay + cy);
